#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minAbsoluteDifference(vector<int>& nums) {
        int total_sum = accumulate(nums.begin(), nums.end(), 0);
        int n = nums.size();
        vector<bool> dp(total_sum / 2 + 1, false);
        dp[0] = true;
        for (int num : nums) {
            for (int j = total_sum / 2; j >= num; --j) {
                dp[j] = dp[j] || dp[j - num];
            }
        }
        for (int j = total_sum / 2; j >= 0; --j) {
            if (dp[j]) {
                return total_sum - 2 * j;
            }
        }
        return 0;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.minAbsoluteDifference(nums);
    cout << ans << "\n";
    return 0;
}
